code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

readline.on('line', (input) => {
    const [num1, num2] = input.split(' ').map(Number);
    const product = num1 * num2;
    console.log(`Product: ${product.toFixed(2)}`);
    readline.close();
});
